{
  "type": "QUIZ",
  "lessonText": "Test your understanding of Python basics with this quiz.",
  "data": {
    "questions": [
      {
        "question": "What is the correct file extension for Python files?",
        "options": ["*.py", "*.python", "*.pt", "*.p"],
        "correctAnswer": 0,
        "explanation": "Python files use the .py extension."
      },
      {
        "question": "Which of the following is a valid variable name in Python?",
        "options": ["1variable", "variable-name", "variable_name", "variable name"],
        "correctAnswer": 2,
        "explanation": "Variable names must start with a letter or underscore and can contain letters, numbers, and underscores."
      },
      {
        "question": "What keyword is used to define a function in Python?",
        "options": ["function", "def", "func", "define"],
        "correctAnswer": 1,
        "explanation": "The 'def' keyword is used to define a function in Python."
      },
      {
        "question": "Which of the following data types is immutable in Python?",
        "options": ["list", "set", "dictionary", "tuple"],
        "correctAnswer": 3,
        "explanation": "Tuples are immutable, meaning their contents cannot be changed after creation."
      }
    ]
  }
}
